    const isLeftMax = new Array(n).fill(false);
    const isRightMax = new Array(n).fill(false);

    // 1. Determine isLeftMax
    // isLeftMax[i] is true if nums[i] is strictly greater than all elements to its left (nums[0]...nums[i-1])
    isLeftMax[0] = true;
    let currentMax = nums[0];
    for (let i = 1; i < n; i++) {
        if (nums[i] > currentMax) {
            isLeftMax[i] = true;
            currentMax = nums[i];
        } else {
            isLeftMax[i] = false;
        }
    }

