    currentMax = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > currentMax) {
            isRightMax[i] = true;
            currentMax = nums[i];
        } else {
            isRightMax[i] = false;
        }
    }

    const result = [];

