            if (nums[i] <= nums[j]) {
                strictlyGreaterThanRight = false;
                break;
            }
        }

        if (strictlyGreaterThanLeft || strictlyGreaterThanRight) {
            finalResult.push(nums[i]);
        }
    }

    return finalResult;
